import java.util.PriorityQueue

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size

    val teleportMap = Array(m) { row ->
        Array(n) { col ->
            val currentVal = grid[row][col]
            val cells = mutableListOf<Pair<Int, Int>>()
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (grid[x][y] <= currentVal) {
                        cells.add(Pair(x, y))
                    }
                }
            }
            cells
        }
    }

    val dist = Array(m) { i ->
        Array(n) { j ->
            Array(k.toInt() + 1) { t ->
                Long.MAX_VALUE
            }
        }
    }
    dist[0][0][0] = 0L

    data class State(val cost: Long, val i: Int, val j: Int, val t: Int) : Comparable<State> {
        override fun compareTo(other: State): Int {
            return this.cost.compareTo(other.cost)
        }
    }

    val pq = PriorityQueue<State>()
    pq.add(State(0, 0, 0, 0))

    while (!pq.isEmpty()) {
        val current = pq.poll()
        if (current.i == m - 1 && current.j == n - 1) {
            return current.cost
        }
        if (current.cost > dist[current.i][current.j][current.t]) {
            continue
        }

        // Regular moves: right and down
        if (current.j + 1 < n) {
            val newCost = current.cost + grid[current.i][current.j + 1]
            if (newCost < dist[current.i][current.j + 1][current.t]) {
                dist[current.i][current.j + 1][current.t] = newCost
                pq.add(State(newCost, current.i, current.j + 1, current.t))
            }
        }
        if (current.i + 1 < m) {
            val newCost = current.cost + grid[current.i + 1][current.j]
            if (newCost < dist[current.i + 1][current.j][current.t]) {
                dist[current.i + 1][current.j][current.t] = newCost
                pq.add(State(newCost, current.i + 1, current.j, current.t))
            }
        }

        // Teleport moves
        if (current.t < k) {
            for ((x, y) in teleportMap[current.i][current.j]) {
                if (current.cost < dist[x][y][current.t + 1]) {
                    dist[x][y][current.t + 1] = current.cost
                    pq.add(State(current.cost, x, y, current.t + 1))
                }
            }
        }
    }

    return -1L
}
