function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;

    // Preprocess teleport_map
    const teleport_map = new Array(m).fill().map(() => new Array(n).fill().map(() => []));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const current_val = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= current_val) {
                        teleport_map[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Dijkstra's algorithm
    const dist = new Array(m).fill().map(() => new Array(n).fill().map(() => new Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    class PriorityQueue {
        constructor() {
            this.heap = [];
        }

        push(value) {
            this.heap.push(value);
            this.bubbleUp(this.heap.length - 1);
        }

        pop() {
            if (this.heap.length === 0) return undefined;
            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.bubbleDown(0);
            return min;
        }

        bubbleUp(index) {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[parentIndex] <= this.heap[index]) break;
                [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
                index = parentIndex;
            }
        }

        bubbleDown(index) {
            const length = this.heap.length;
            while (index < length) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < length && this.heap[left] < this.heap[smallest]) {
                    smallest = left;
                }
                if (right < length && this.heap[right] < this.heap[smallest]) {
                    smallest = right;
                }
                if (smallest === index) break;
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            }
        }

        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const pq = new PriorityQueue();
    pq.push([0, 0, 0, 0]);

    while (!pq.isEmpty()) {
        const [cost, i, j, t] = pq.pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) {
            continue;
        }

        // Process normal moves
        if (j + 1 < n) {
            const new_cost = cost + grid[i][j + 1];
            if (new_cost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = new_cost;
                pq.push([new_cost, i, j + 1, t]);
            }
        }
        if (i + 1 < m) {
            const new_cost = cost + grid[i + 1][j];
            if (new_cost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = new_cost;
                pq.push([new_cost, i + 1, j, t]);
