import java.util.*

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size

    // Preprocess teleport_map
    val teleportMap = Array(m) { row ->
        Array(n) { col ->
            val currentVal = grid[row][col]
            val list = mutableListOf<Pair<Int, Int>>()
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (grid[x][y] <= currentVal) {
                        list.add(Pair(x, y))
                    }
                }
            }
            list
        }
    }

    // Initialize distance array
    val dist = Array(m) { row ->
        Array(n) { col ->
            Array(k.toInt() + 1) { t -> Long.MAX_VALUE }
        }
    }
    dist[0][0][0] = 0L

    // Priority queue
    val pq = PriorityQueue<MutableList<Long>>(Comparator { a, b ->
        if (a[0] < b[0]) -1
        else if (a[0] > b[0]) 1
        else 0
    })

    pq.add(mutableListOf(0L, 0L, 0L, 0L))

    while (!pq.isEmpty()) {
        val current = pq.poll()
        val cost = current[0]
        val i = current[1].toInt()
        val j = current[2].toInt()
        val t = current[3].toInt()

        if (i == m - 1 && j == n - 1) {
            return cost
        }

        if (cost > dist[i][j][t]) {
            continue
        }

        // Normal moves
        if (j + 1 < n) {
            val newCost = cost + grid[i][j + 1]
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost
                pq.add(mutableListOf(newCost, i.toLong(), (j + 1).toLong(), t.toLong()))
