        if (i + 1 < m) {
            val newCost = cost + grid[i + 1][j]
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost
                pq.add(mutableListOf(newCost, (i + 1).toLong(), j.toLong(), t.toLong()))
            }
        }

        // Teleport moves
        if (t < k) {
            for (cell in teleportMap[i][j]) {
                val x = cell.first
                val y = cell.second
                if (cost < dist[x][y][t + 1]) {
                    dist[x][y][t + 1] = cost
                    pq.add(mutableListOf(cost, x.toLong(), y.toLong(), (t + 1).toLong()))
                }
            }
        }
    }

    return -1L
}
