class PriorityQueue {
    private val heap: MutableList<MutableList<Long>>

    constructor() {
        this.heap = mutableListOf()
    }

    fun push(value: MutableList<Long>) {
        heap.add(value)
        bubbleUp(heap.size - 1)
    }

    fun pop(): MutableList<Long>? {
        if (heap.isEmpty()) return null
        val min = heap[0]
        heap[0] = heap.last()
        heap.removeLast()
        bubbleDown(0)
        return min
    }

    private fun bubbleUp(index: Int) {
