                smallest = right
            }
            if (smallest == index) break
            swap(index, smallest)
            index = smallest
        }
    }

    private fun swap(a: Int, b: Int) {
        val temp = heap[a]
        heap[a] = heap[b]
        heap[b] = temp
    }

    fun isEmpty(): Boolean {
        return heap.isEmpty()
    }
