fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size

    val teleportMap = Array(m) { Array(n) { mutableListOf<IntArray>() } }

    for (i in 0 until m) {
        for (j in 0 until n) {
            val currentVal = grid[i][j]
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (grid[x][y] <= currentVal) {
                        teleportMap[i][j].add(intArrayOf(x, y))
                    }
                }
            }
        }
    }

    val dist = Array(m) { Array(n) { Array(k.toInt() + 1) { Long.MAX_VALUE } } }
    dist[0][0][0] = 0L

    class PriorityQueue {
        private val heap: MutableList<Array<Long>> = mutableListOf()

        fun push(value: Array<Long>) {
            heap.add(value)
            bubbleUp(heap.size - 1)
        }

        fun pop(): Array<Long>? {
            if (heap.isEmpty()) return null
            val min = heap[0]
            heap[0] = heap.last()
            heap.removeLast()
            bubbleDown(0)
            return min
        }

        private fun bubbleUp(index: Int) {
            while (index > 0) {
                val parentIndex = (index - 1) / 2
                if (heap[parentIndex][0] <= heap[index][0]) break
                val temp = heap[parentIndex]
                heap[parentIndex] = heap[index]
                heap[index] = temp
                index = parentIndex
            }
        }

        private fun bubbleDown(index: Int) {
            val length = heap.size
            while (index < length) {
                val left = 2 * index + 1
                val right = 2 * index + 2
                var smallest = index
                if (left < length && heap[left][0] < heap[smallest][0]) {
                    smallest = left
                }
                if (right < length && heap[right][0] < heap[smallest][0]) {
                    smallest = right
                }
                if (smallest == index) break
                val temp = heap[index]
                heap[index] = heap[smallest]
                heap[smallest] = temp
                index = smallest
            }
        }

        fun isEmpty(): Boolean {
            return heap.isEmpty()
        }
    }

