            if (right < length && heap[right][0] < heap[smallest][0]) {
                smallest = right
            }
            if (smallest == index) break
            val temp = heap[index]
            heap[index] = heap[smallest]
            heap[smallest] = temp
            index = smallest
        }
    }

    fun isEmpty(): Boolean {
        return heap.isEmpty()
    }
